#include<bits/stdc++.h>
using namespace std;
const int N=400;
int n,a[N],x=0,ans=0;
vector<int> ve;
int main(void){
	cin>>n;
	while(n--)cin>>a[n],x=(x+a[n])%360,ve.push_back(x);
	ve.push_back(0),ve.push_back(360);
	sort(ve.begin(),ve.end());
	for(int i=0;i<ve.size()-1;i++)ans=max(ans,ve[i+1]-ve[i]);	
	cout<<ans;
	return false;
}
